                        }
                    }
                }
            return Pair(ruleExecutionContext.rootNode.text.replace("\n", ruleExecutionContext.determineLineSeparator(code.content)), errors.toList())
        }

        do {
            val (result, errors) = formatStep(currentCode)
            lastErrors = errors.sortedWith { (l), (r) -> if (l.line != r.line) l.line - r.line else l.col - r.col }
            lastMutated = errors.any { it.second }
            formattedCode = result
            rerunCount++
